questions = [
  {"id":266,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which Windows hardening step disables the automatic execution of code when removable media is inserted?","options":{"A":"BitLocker","B":"Autorun/Autoplay disable","C":"AppLocker","D":"Windows Defender"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Disabling Autorun/Autoplay prevents malicious code on USB drives or optical media from executing automatically when inserted, a common malware delivery technique.","A":"BitLocker encrypts drives; it doesn't control auto-execution.","B":"Correct. Disabling Autorun stops removable media code from executing automatically.","C":"AppLocker controls which applications can run; it doesn't specifically target autorun behavior.","D":"Windows Defender provides antimalware scanning; disabling autorun is a separate hardening step."}},
  {"id":267,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which configuration on a mobile device enforces encryption, remote wipe, and screen lock policies?","options":{"A":"Application allowlisting","B":"MDM (Mobile Device Management)","C":"VPN client","D":"Containerization"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"MDM solutions enforce security policies on mobile devices including encryption, screen lock, remote wipe, certificate deployment, and application management.","A":"Application allowlisting controls which apps can run; it is a feature within MDM but not the full solution.","B":"Correct. MDM enforces comprehensive mobile security policies including encryption and remote wipe.","C":"A VPN client secures network traffic; it doesn't enforce device security policies.","D":"Containerization on mobile separates personal and work data; MDM manages the device-level controls."}},
  {"id":268,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which protocol should replace Telnet for secure remote administration of network devices?","options":{"A":"FTP","B":"HTTP","C":"SSH","D":"SNMP v1"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"SSH (Secure Shell) encrypts the entire session including authentication, replacing Telnet which transmits everything in cleartext including credentials.","A":"FTP transfers files in cleartext; SFTP or FTPS should be used for secure file transfer.","B":"HTTP is cleartext web traffic; not used for device administration.","C":"Correct. SSH replaces Telnet with encrypted remote administration sessions.","D":"SNMP v1 sends community strings in cleartext; SNMPv3 should be used instead."}},
  {"id":269,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"A company deploys Group Policy to disable USB mass storage on all workstations. This implements which security control?","options":{"A":"DLP","B":"Endpoint hardening","C":"Network segmentation","D":"Application control"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Disabling USB mass storage through Group Policy is a form of endpoint hardening — reducing the attack surface by limiting potentially dangerous hardware capabilities on workstations.","A":"DLP prevents data exfiltration; disabling USB is a hardening/configuration control that supports DLP goals.","B":"Correct. Using Group Policy to disable USB ports is endpoint hardening.","C":"Network segmentation divides networks; USB control is endpoint-level.","D":"Application control manages which software can execute; USB control is a hardware policy."}},
  {"id":270,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which wireless security improvement does WPA3 provide over WPA2?","options":{"A":"Uses RC4 instead of AES for faster encryption","B":"SAE (Simultaneous Authentication of Equals) replaces PSK for stronger handshake","C":"Removes the need for passwords entirely","D":"Uses WEP compatibility mode"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"WPA3 replaces the WPA2 Pre-Shared Key (PSK) handshake with SAE (Dragonfly handshake), which is resistant to offline dictionary attacks and provides forward secrecy.","A":"WPA3 uses AES; RC4 is used in deprecated WEP — WPA3 does not use RC4.","B":"Correct. SAE in WPA3 provides stronger key establishment resistant to offline attacks.","C":"WPA3 still uses passwords but protects them better with SAE.","D":"WEP compatibility mode is a WPA2 option, not a WPA3 feature."}},
  {"id":271,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which DNS security feature prevents clients from receiving malicious or spoofed DNS responses?","options":{"A":"DNSSEC","B":"DNS over HTTPS","C":"DNS filtering","D":"Split DNS"},"correct_answer":"A","difficulty":3,"explanations":{"correct":"DNSSEC uses digital signatures to validate DNS responses, ensuring they are authentic and haven't been tampered with, protecting against cache poisoning and spoofing attacks.","A":"Correct. DNSSEC validates DNS record authenticity using digital signatures.","B":"DNS over HTTPS (DoH) encrypts DNS queries for privacy; it doesn't validate record authenticity.","C":"DNS filtering blocks known-bad domains; it doesn't validate record authenticity.","D":"Split DNS uses different zones for internal and external queries; not a security validation mechanism."}},
  {"id":272,"domain":4,"subdomain":"4.2","objective":"Explain the security implications of proper hardware, software, and data asset management","stem":"When disposing of a hard drive containing sensitive data, which method ensures data cannot be recovered?","options":{"A":"Standard deletion","B":"Quick format","C":"Degaussing or physical destruction","D":"Encrypting then deleting"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Degaussing destroys magnetic media data using a strong magnetic field; physical destruction (shredding, crushing) physically destroys the media. Both ensure data cannot be recovered even with forensic tools.","A":"Standard deletion only removes file system pointers; data remains recoverable.","B":"Quick format removes the file system structure but leaves data on the disk.","C":"Correct. Degaussing or physical destruction permanently prevents data recovery.","D":"Encrypting then deleting is a reasonable approach but relies on key destruction; physical destruction is more certain."}},
  {"id":273,"domain":4,"subdomain":"4.2","objective":"Explain the security implications of proper hardware, software, and data asset management","stem":"Which asset disposal method overwrites storage media multiple times with random data patterns?","options":{"A":"Degaussing","B":"Physical destruction","C":"Data wiping/sanitization","D":"Reformatting"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Data wiping (sanitization) overwrites storage media with random patterns (often multiple passes) per standards like NIST SP 800-88, making data unrecoverable while keeping the hardware reusable.","A":"Degaussing uses magnetic fields to destroy data on magnetic media; SSDs and optical media require other methods.","B":"Physical destruction destroys hardware; data wiping keeps hardware usable.","C":"Correct. Data wiping overwrites media with patterns to sanitize it while preserving hardware.","D":"Reformatting only removes file system structure; data remains recoverable."}},
  {"id":274,"domain":4,"subdomain":"4.2","objective":"Explain the security implications of proper hardware, software, and data asset management","stem":"An IT department maintains a database of all hardware assets including serial numbers, assigned users, and location. This is a:","options":{"A":"CMDB","B":"SIEM","C":"Asset register / inventory","D":"Patch management system"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"An asset register (or asset inventory) tracks hardware assets including identification details, location, owner, and status. It is foundational for security management and incident response.","A":"A CMDB (Configuration Management Database) tracks configuration items and relationships; while related, the described database is specifically asset inventory.","B":"SIEM aggregates security logs; it does not track physical hardware assets.","C":"Correct. A database tracking hardware assets with serial numbers and locations is an asset inventory/register.","D":"A patch management system tracks software patches; not hardware asset records."}},
  {"id":275,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which vulnerability management metric measures the time between when a vulnerability is published and when it is patched?","options":{"A":"CVSS score","B":"Mean Time to Patch (MTTP)","C":"Exposure window","D":"Risk score"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Mean Time to Patch (MTTP) measures the average time from vulnerability disclosure to patch deployment, indicating how quickly an organization closes known vulnerabilities.","A":"CVSS score rates vulnerability severity; it doesn't measure patching speed.","B":"Correct. MTTP measures the average time from vulnerability disclosure to patching.","C":"Exposure window describes the period a system is vulnerable; MTTP is the formal metric name.","D":"Risk score combines likelihood and impact; not specifically a patching time metric."}},
  {"id":276,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which CVSS metric range indicates a Critical severity vulnerability?","options":{"A":"0.1–3.9","B":"4.0–6.9","C":"7.0–8.9","D":"9.0–10.0"},"correct_answer":"D","difficulty":2,"explanations":{"correct":"The CVSS v3.x scoring ranges: None (0.0), Low (0.1-3.9), Medium (4.0-6.9), High (7.0-8.9), Critical (9.0-10.0). Critical vulnerabilities typically allow remote unauthenticated exploitation.","A":"0.1-3.9 is Low severity.","B":"4.0-6.9 is Medium severity.","C":"7.0-8.9 is High severity.","D":"Correct. 9.0-10.0 is Critical severity in CVSS v3.x scoring."}},
  {"id":277,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"A vulnerability scanner identifies a vulnerability that doesn't actually exist on the target system. This is called a:","options":{"A":"True positive","B":"False positive","C":"True negative","D":"False negative"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A false positive is when a scanner reports a vulnerability that does not actually exist. These waste analyst time and must be validated before remediation.","A":"True positive: scanner correctly identifies a real vulnerability.","B":"Correct. A false positive is an alert for a vulnerability that doesn't exist.","C":"True negative: scanner correctly reports no vulnerability where none exists.","D":"False negative: scanner fails to report a vulnerability that does exist — more dangerous than false positives."}},
  {"id":278,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which approach to vulnerability scanning involves authenticated access to the target system for more thorough results?","options":{"A":"External scan","B":"Unauthenticated scan","C":"Credentialed scan","D":"Passive scan"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Credentialed (authenticated) scans log into target systems with valid credentials, enabling deeper inspection of installed software versions, configurations, and registry settings — producing more accurate and complete results.","A":"External scans test from outside the network perimeter but may be unauthenticated.","B":"Unauthenticated scans probe from the outside without credentials, missing many vulnerabilities.","C":"Correct. Credentialed scans use valid credentials for thorough internal system assessment.","D":"Passive scans observe network traffic without actively probing; less comprehensive than active credentialed scans."}},
  {"id":279,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which vulnerability management activity uses known threat actor TTPs to proactively search for indicators of compromise that automated tools may have missed?","options":{"A":"Vulnerability scanning","B":"Penetration testing","C":"Threat hunting","D":"Red team exercise"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Threat hunting is a proactive, human-led search for threats in an environment using known attacker TTPs and IoCs, looking for adversaries that have evaded automated detection.","A":"Vulnerability scanning identifies technical vulnerabilities; threat hunting searches for active adversaries.","B":"Penetration testing simulates attacks to find vulnerabilities; threat hunting searches for existing compromises.","C":"Correct. Threat hunting proactively seeks hidden adversaries using TTPs and IoCs.","D":"Red team exercises simulate full attack campaigns; threat hunting specifically searches for existing compromises."}},
  {"id":280,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"A bug bounty program incentivizes which group to find and responsibly disclose vulnerabilities?","options":{"A":"Internal penetration testers","B":"External security researchers","C":"Compliance auditors","D":"Threat hunting teams"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Bug bounty programs offer financial rewards to external security researchers who discover and responsibly disclose vulnerabilities, providing continuous security testing from a diverse pool of talent.","A":"Internal penetration testers are employees; bug bounties are for external researchers.","B":"Correct. Bug bounty programs reward external security researchers for responsible disclosure.","C":"Compliance auditors assess regulatory adherence; they don't participate in bug bounties.","D":"Threat hunting teams are internal; bug bounties target external researchers."}},
  {"id":281,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which tool aggregates logs from multiple sources, correlates events, and generates alerts for security incidents?","options":{"A":"IDS","B":"Firewall","C":"SIEM","D":"Vulnerability scanner"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"A SIEM (Security Information and Event Management) system collects and aggregates logs from across the environment, correlates events using rules, and generates alerts for potential security incidents.","A":"An IDS monitors network traffic for intrusion signatures; it doesn't aggregate multi-source logs.","B":"A firewall controls traffic; it generates logs but doesn't aggregate or correlate them.","C":"Correct. SIEM aggregates, correlates, and alerts on security events from multiple log sources.","D":"A vulnerability scanner identifies vulnerabilities; it doesn't monitor or correlate security events."}},
  {"id":282,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which log format exports network flow data (source/destination IP, ports, bytes transferred) from routers and switches for analysis?","options":{"A":"Syslog","B":"NetFlow/IPFIX","C":"CEF","D":"SNMP trap"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"NetFlow (Cisco) and IPFIX (standardized version) export flow records including source/destination IPs, ports, protocols, and byte counts from routers and switches for traffic analysis and anomaly detection.","A":"Syslog is a generic log transport protocol for system messages; not specifically for flow data.","B":"Correct. NetFlow/IPFIX exports network flow records from routing devices.","C":"CEF (Common Event Format) is a log format for security events; not flow data from routers.","D":"SNMP traps are event notifications from network devices; not flow record exports."}},
  {"id":283,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which monitoring approach detects threats by learning normal behavior and alerting on deviations?","options":{"A":"Signature-based detection","B":"Heuristic analysis","C":"Anomaly/behavior-based detection","D":"Rule-based detection"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Anomaly-based (behavior-based) detection establishes a baseline of normal behavior and alerts when activity deviates significantly from that baseline, enabling detection of previously unknown threats.","A":"Signature-based detection matches traffic against known threat signatures; it misses new/unknown attacks.","B":"Heuristic analysis evaluates code characteristics to detect suspicious behavior without exact signatures.","C":"Correct. Anomaly-based detection baselines normal behavior and alerts on deviations.","D":"Rule-based detection uses defined rules (like signature-based); it doesn't adapt to new behaviors."}},
  {"id":284,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which Windows log contains records of user logon/logoff events, privilege use, and account management actions?","options":{"A":"System log","B":"Application log","C":"Security log","D":"Setup log"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"The Windows Security Event Log (Security.evtx) records authentication events (logon/logoff), privilege use, account management, policy changes, and object access — the primary log for security investigations.","A":"System log records OS and driver events; not specifically authentication events.","B":"Application log records application-specific events; not authentication events.","C":"Correct. The Security log records authentication, privilege use, and account management events.","D":"Setup log records installation events; not security events."}},
  {"id":285,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which concept describes sending all syslogs from network devices to a central server for storage and analysis?","options":{"A":"SIEM","B":"Log aggregation","C":"Event correlation","D":"Alert triage"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Log aggregation centralizes logs from multiple sources (firewalls, servers, applications) into a single platform for unified analysis, retention, and SIEM correlation.","A":"SIEM provides aggregation plus correlation and alerting; log aggregation is the collection component.","B":"Correct. Log aggregation collects and centralizes logs from multiple sources.","C":"Event correlation analyzes aggregated logs to identify related events; it depends on aggregation first.","D":"Alert triage is the process of reviewing and prioritizing alerts; it comes after aggregation and correlation."}},
  {"id":286,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Email security gateway identifies a message with a DMARC fail result from a domain claiming to be from a bank. What action should the gateway take?","options":{"A":"Deliver the message normally","B":"Quarantine or reject the message","C":"Forward to the original sender for review","D":"Add a disclaimer and deliver"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"DMARC FAIL means the message failed both SPF and DKIM alignment checks, indicating the sender is not authorized by the domain. The gateway should quarantine or reject such messages per the domain's DMARC policy.","A":"Delivering a DMARC-failing message allows spoofed/phishing emails to reach users.","B":"Correct. DMARC failure indicates spoofing; messages should be quarantined or rejected.","C":"Forwarding to the sender is not a standard email gateway response action.","D":"Adding a disclaimer and delivering still exposes users to phishing content."}},
  {"id":287,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which tool inspects encrypted HTTPS traffic by acting as a trusted intermediary, decrypting, inspecting, and re-encrypting traffic?","options":{"A":"Network TAP","B":"TLS/SSL inspection (break-and-inspect)","C":"DNSSEC","D":"Certificate pinning"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"TLS inspection (break-and-inspect or SSL decryption) uses a trusted certificate to decrypt HTTPS traffic, inspect it for threats, then re-encrypt it before forwarding. It enables security tools to inspect encrypted traffic.","A":"A network TAP copies traffic passively; it cannot decrypt TLS traffic.","B":"Correct. TLS break-and-inspect decrypts, inspects, and re-encrypts HTTPS traffic.","C":"DNSSEC validates DNS record authenticity; it doesn't inspect encrypted traffic.","D":"Certificate pinning prevents MITM by restricting trusted certificates; it would block TLS inspection."}},
  {"id":288,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"A company wants to prevent sensitive files from being uploaded to unauthorized cloud storage. Which technology BEST addresses this?","options":{"A":"Firewall","B":"IPS","C":"DLP","D":"NAC"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"DLP (Data Loss Prevention) inspects outbound traffic and file operations, detecting sensitive content and blocking unauthorized uploads based on content policies.","A":"A firewall can block entire cloud storage domains but cannot inspect content within allowed connections.","B":"IPS blocks attack signatures but doesn't inspect for specific sensitive data content in legitimate traffic.","C":"Correct. DLP inspects content and blocks unauthorized transmission of sensitive data.","D":"NAC controls network access based on device health; it doesn't inspect file content."}},
  {"id":289,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which DNS security technique redirects queries for known malicious domains to a controlled IP address, allowing incident responders to monitor and analyze infected systems?","options":{"A":"DNSSEC","B":"DNS over HTTPS","C":"DNS sinkholing","D":"Split DNS"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"DNS sinkholing redirects DNS queries for malicious C2 domains to a controlled sinkhole IP, allowing security teams to identify infected systems that are attempting to reach the malicious domain.","A":"DNSSEC validates record authenticity; it doesn't redirect queries.","B":"DoH encrypts DNS queries; it doesn't redirect to sinkhole IPs.","C":"Correct. DNS sinkholing redirects malicious domain queries to a controlled IP for monitoring.","D":"Split DNS uses different DNS zones internally and externally; not specifically for malicious domain redirection."}},
  {"id":290,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which authentication factor type is a hardware token that generates a time-based one-time password?","options":{"A":"Something you know","B":"Something you have","C":"Something you are","D":"Somewhere you are"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"A hardware token is a physical device (something you have). It generates TOTPs (Time-based One-Time Passwords) using the TOTP algorithm, providing a second factor for MFA.","A":"Something you know is a knowledge factor — passwords, PINs, security questions.","B":"Correct. A hardware token is a possession factor (something you have).","C":"Something you are is a biometric factor — fingerprint, face, iris.","D":"Somewhere you are is a location factor — GPS location, network-based geolocation."}},
  {"id":291,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which protocol allows a user to authenticate once and gain access to multiple applications without re-entering credentials?","options":{"A":"RADIUS","B":"LDAP","C":"SSO (Single Sign-On)","D":"SAML"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Single Sign-On (SSO) allows users to authenticate once with a central identity provider and then access multiple applications without re-authenticating for each one.","A":"RADIUS is an authentication protocol for network access; it doesn't provide SSO across applications.","B":"LDAP is a directory protocol; it stores identity information but doesn't provide SSO by itself.","C":"Correct. SSO enables one authentication to access multiple applications.","D":"SAML is a protocol used to implement SSO but SSO is the capability; SAML is one mechanism."}},
  {"id":292,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which open standard allows web applications to securely delegate authorization to a third party without sharing passwords?","options":{"A":"SAML 2.0","B":"OAuth 2.0","C":"LDAP","D":"RADIUS"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"OAuth 2.0 is an authorization framework that allows applications to request limited access to a user's resources on another service without the user sharing their password with the requesting application.","A":"SAML 2.0 is used for SSO and authentication federation; OAuth is specifically for authorization delegation.","B":"Correct. OAuth 2.0 enables authorization delegation without password sharing.","C":"LDAP is a directory protocol; it doesn't provide authorization delegation.","D":"RADIUS handles network access authentication; it doesn't enable web-based authorization delegation."}},
  {"id":293,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which identity standard provides SSO for web applications using XML-based assertions to pass authentication information?","options":{"A":"OAuth 2.0","B":"OpenID Connect","C":"SAML 2.0","D":"Kerberos"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"SAML (Security Assertion Markup Language) 2.0 uses XML-based assertions to pass authentication and authorization information between an identity provider (IdP) and service providers (SPs) for web SSO.","A":"OAuth 2.0 handles authorization; SAML handles authentication/SSO.","B":"OpenID Connect (OIDC) is a modern authentication layer on top of OAuth 2.0 using JSON tokens.","C":"Correct. SAML 2.0 uses XML assertions for web SSO between IdPs and SPs.","D":"Kerberos provides SSO for internal networks using tickets; SAML is for web/federated SSO."}},
  {"id":294,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which MFA method is considered LEAST secure due to susceptibility to SIM swapping attacks?","options":{"A":"Hardware token (TOTP)","B":"Authenticator app (TOTP)","C":"SMS one-time password","D":"FIDO2 passkey"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"SMS OTP is the least secure MFA method because attackers can SIM swap (convince a carrier to transfer the victim's phone number) to intercept SMS codes. It is still better than no MFA.","A":"Hardware tokens are not tied to a phone number and cannot be SIM swapped.","B":"Authenticator apps are also not tied to the phone number; they use TOTP synchronized with a seed.","C":"Correct. SMS OTP is vulnerable to SIM swapping, making it the least secure MFA method.","D":"FIDO2 passkeys use public key cryptography and are phishing-resistant — the most secure MFA method."}},
  {"id":295,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which PAM capability provides temporary, time-limited administrative access that expires automatically?","options":{"A":"Password vaulting","B":"Session recording","C":"Just-in-time (JIT) access","D":"Credential brokering"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Just-in-time (JIT) access provides elevated privileges only when needed and for a specific time window, automatically revoking them when the window expires, reducing persistent privilege exposure.","A":"Password vaulting stores and rotates privileged credentials; JIT is about time-limited access.","B":"Session recording captures privileged sessions for audit; it doesn't control access duration.","C":"Correct. JIT access grants temporary, time-limited elevated privileges on demand.","D":"Credential brokering provides credentials on request without users seeing them; JIT is specifically about time-limited access."}},
  {"id":296,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"An attacker tries the same few common passwords against many different accounts to avoid lockout. This is called:","options":{"A":"Brute force","B":"Credential stuffing","C":"Password spraying","D":"Dictionary attack"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Password spraying tries a small number of common passwords (e.g., 'Winter2024!') against a large number of accounts, staying under account lockout thresholds while maximizing coverage.","A":"Brute force tries all possible combinations against one account; it triggers lockout.","B":"Credential stuffing uses known username/password pairs from data breaches.","C":"Correct. Password spraying uses few passwords against many accounts to avoid lockout.","D":"Dictionary attack tries many passwords from a wordlist against one account; lockout is a risk."}},
  {"id":297,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which process ensures that user access rights are reviewed and confirmed or revoked on a regular schedule?","options":{"A":"Provisioning","B":"Access recertification (access review)","C":"Deprovisioning","D":"Separation of duties"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Access recertification (or access review) is the periodic review of user access rights by managers or data owners to confirm that access is still appropriate and remove any unnecessary permissions.","A":"Provisioning is the initial granting of access; recertification is the ongoing review.","B":"Correct. Access recertification periodically validates and adjusts user access rights.","C":"Deprovisioning removes access when a user leaves; recertification is a periodic review during employment.","D":"Separation of duties prevents one person from controlling a full process; not about periodic review."}},
  {"id":298,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which authentication method uses public key cryptography so a user never sends a password over the network?","options":{"A":"Password-based authentication","B":"Certificate-based authentication","C":"TOTP","D":"Smart card with PIN"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Certificate-based authentication uses public key cryptography — the client proves identity by signing a challenge with their private key. No password is transmitted; the server verifies with the public key in the certificate.","A":"Password-based authentication transmits (hashed) credentials; certificate-based uses key pairs.","B":"Correct. Certificate-based authentication uses public key cryptography and never transmits a password.","C":"TOTP transmits a time-based code over the network; not public key cryptography.","D":"Smart card with PIN combines possession (smart card with certificate) and knowledge (PIN); certificate-based is the cryptographic mechanism used."}},
  {"id":299,"domain":4,"subdomain":"4.7","objective":"Explain the importance of automation and orchestration","stem":"Which tool automates security operations by executing predefined workflows in response to security alerts?","options":{"A":"SIEM","B":"SOAR","C":"IPS","D":"EDR"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"SOAR (Security Orchestration, Automation, and Response) automates security response workflows (playbooks) triggered by SIEM alerts, reducing response time and analyst workload.","A":"SIEM collects, correlates, and alerts; SOAR automates the response actions.","B":"Correct. SOAR orchestrates and automates security response using playbooks.","C":"IPS automatically blocks network threats; it doesn't orchestrate complex multi-step security workflows.","D":"EDR responds to endpoint threats automatically; SOAR orchestrates cross-platform multi-step responses."}},
  {"id":300,"domain":4,"subdomain":"4.7","objective":"Explain the importance of automation and orchestration","stem":"Which benefit of security automation MOST directly reduces analyst burnout?","options":{"A":"Increasing network throughput","B":"Reducing repetitive manual tasks and alert volume","C":"Replacing human judgment for all decisions","D":"Eliminating the need for security policies"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Security automation reduces repetitive manual tasks (like log review, ticket creation, IOC enrichment) and filters noise, allowing analysts to focus on complex investigations rather than routine work.","A":"Network throughput is a networking metric; automation addresses analyst efficiency.","B":"Correct. Reducing repetitive tasks and alert noise directly reduces analyst burnout.","C":"Automation handles routine tasks; complex decisions still require human judgment.","D":"Security policies are still required; automation helps enforce them more consistently."}},
  {"id":301,"domain":4,"subdomain":"4.7","objective":"Explain the importance of automation and orchestration","stem":"A SOAR playbook automatically quarantines an endpoint when EDR detects malware. Which automation benefit does this represent?","options":{"A":"Scalability","B":"Faster response time (speed of response)","C":"Reduced licensing costs","D":"Improved threat intelligence"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Automated quarantine in response to malware detection happens in seconds, far faster than a human analyst could respond. Speed of response is a primary benefit of automation.","A":"Scalability means handling increased volume without proportional resource increases; speed is the primary benefit here.","B":"Correct. Automated quarantine achieves near-instant response, a key automation benefit.","C":"Automation may reduce long-term costs but that's not the primary benefit here.","D":"Threat intelligence is the context about threats; the benefit here is response speed."}},
  {"id":302,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"Which phase of the incident response lifecycle focuses on identifying the scope and nature of an incident?","options":{"A":"Preparation","B":"Detection and analysis","C":"Containment","D":"Eradication"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Detection and analysis involves identifying that an incident has occurred, analyzing evidence to determine its scope, impact, and nature, and documenting findings.","A":"Preparation involves building capabilities before incidents occur (training, tools, playbooks).","B":"Correct. Detection and analysis identifies and characterizes the incident.","C":"Containment limits the spread after the incident is identified.","D":"Eradication removes the threat from the environment after containment."}},
  {"id":303,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"After malware is discovered on a network, the IR team disconnects infected systems from the network. This is which IR phase?","options":{"A":"Detection","B":"Eradication","C":"Containment","D":"Recovery"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Containment prevents the spread of the incident by isolating affected systems. Disconnecting infected systems from the network is a classic containment action.","A":"Detection identifies that an incident occurred; containment comes after detection.","B":"Eradication removes the threat (deletes malware, resets credentials); containment stops the spread first.","C":"Correct. Isolating infected systems to stop spread is a containment action.","D":"Recovery restores systems to normal operation after eradication."}},
  {"id":304,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"During a forensic investigation, which principle ensures that evidence is handled properly and its integrity is maintained throughout?","options":{"A":"Order of volatility","B":"Chain of custody","C":"Non-repudiation","D":"Legal hold"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Chain of custody documents who handled evidence, when, and how, ensuring evidence integrity and admissibility in legal proceedings. Breaking chain of custody can make evidence inadmissible.","A":"Order of volatility determines which evidence to collect first (most volatile first); chain of custody tracks its handling.","B":"Correct. Chain of custody documents evidence handling to ensure integrity and admissibility.","C":"Non-repudiation prevents denial of actions; it's a security property, not a forensic evidence principle.","D":"Legal hold preserves evidence relevant to litigation; chain of custody tracks how it's handled."}},
  {"id":305,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"In digital forensics, which data source should be collected FIRST due to its volatility?","options":{"A":"Hard drive image","B":"Log files","C":"RAM contents","D":"Backup tapes"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"The order of volatility places RAM first — it is lost when power is removed. RAM may contain running processes, network connections, encryption keys, and other forensic evidence not found on disk.","A":"Hard drive contents persist after power off; they are collected after volatile data.","B":"Log files persist on disk; less volatile than RAM.","C":"Correct. RAM is the most volatile — lost on power off, collected first per order of volatility.","D":"Backup tapes are the least volatile; collected last."}},
  {"id":306,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"Which IR activity involves tabletop exercises and simulated incident scenarios to test the team's readiness?","options":{"A":"Lessons learned","B":"Containment","C":"Incident response testing/training","D":"Threat hunting"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"IR testing and training includes tabletop exercises, simulations, and drills that test the team's readiness and validate playbooks without a real incident occurring.","A":"Lessons learned occurs after an actual incident, not as preparation/training.","B":"Containment is an IR phase during an actual incident.","C":"Correct. Tabletop exercises and simulations are IR training/testing activities.","D":"Threat hunting proactively searches for threats in the environment; not an IR readiness exercise."}},
  {"id":307,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"Which type of forensic evidence is collected by analyzing disk images without modifying the original media?","options":{"A":"Volatile evidence","B":"Network evidence","C":"Non-volatile (disk) evidence","D":"Testimonial evidence"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Non-volatile evidence persists on storage media (hard drives, SSDs) and is collected by creating a bit-for-bit forensic image of the disk, allowing analysis without altering the original.","A":"Volatile evidence is found in RAM and temporary storage — lost on power off.","B":"Network evidence is collected from captures, logs, and flow data from network devices.","C":"Correct. Disk-based non-volatile evidence is collected via forensic imaging of storage media.","D":"Testimonial evidence is witness statements; not a digital forensics evidence type."}},
  {"id":308,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"After an incident is resolved, the team documents what happened, what worked, and what should be improved. This is called:","options":{"A":"Root cause analysis","B":"Lessons learned (post-incident review)","C":"Threat modeling","D":"Risk assessment"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"A lessons learned (post-incident review or post-mortem) documents the incident timeline, identifies what worked well, what failed, and determines improvements to prevent recurrence.","A":"Root cause analysis identifies the technical cause; lessons learned is the broader review process.","B":"Correct. Lessons learned is the post-incident review process for documentation and improvement.","C":"Threat modeling is a proactive process to identify potential threats before incidents occur.","D":"Risk assessment evaluates risks; it is not a post-incident activity."}},
  {"id":309,"domain":4,"subdomain":"4.9","objective":"Use data sources to support an investigation","stem":"Which log source would BEST show when a specific file was accessed on a Windows system?","options":{"A":"Network flow data","B":"Windows Security Event Log with object access auditing","C":"DHCP server logs","D":"DNS query logs"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Windows Security Event Log with object access auditing enabled (Event ID 4663) records when files and folders are accessed, by whom, and what operations were performed.","A":"Network flow data shows connections between systems; not file access on a local system.","B":"Correct. Windows Security Event Log with object access auditing records file access events.","C":"DHCP logs record IP address assignments; not file access.","D":"DNS logs record domain name queries; not local file access."}},
  {"id":310,"domain":4,"subdomain":"4.9","objective":"Use data sources to support an investigation","stem":"Which tool reconstructs network sessions from captured packet data to show the full content of a communication?","options":{"A":"Nmap","B":"Wireshark / packet analyzer","C":"Nessus","D":"Metasploit"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Wireshark and similar packet analyzers capture and decode network traffic, allowing investigators to reconstruct sessions, view payload content, and analyze protocols during forensic investigations.","A":"Nmap is a port and service scanner; it doesn't capture or analyze traffic content.","B":"Correct. Wireshark captures and decodes packets, enabling session reconstruction.","C":"Nessus is a vulnerability scanner; not a packet capture tool.","D":"Metasploit is an exploit framework; not for traffic capture and analysis."}},
  {"id":311,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which vulnerability management priority framework considers exploitability, asset criticality, and business impact when ranking what to patch first?","options":{"A":"CVSS only","B":"Risk-based prioritization","C":"FIFO (first in, first out)","D":"Vendor advisory only"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Risk-based prioritization combines vulnerability severity (CVSS), asset criticality to the business, threat intelligence (active exploitation), and business impact to determine the most important vulnerabilities to fix first.","A":"CVSS alone provides technical severity but ignores business context and asset criticality.","B":"Correct. Risk-based prioritization considers exploitability, asset criticality, and business impact.","C":"FIFO doesn't consider criticality; critical vulnerabilities would wait behind trivial ones.","D":"Vendor advisories provide severity context but don't account for organizational asset criticality."}},
  {"id":312,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"A company uses an external identity provider (like Azure AD) to authenticate users for its web app. This is called:","options":{"A":"On-premises authentication","B":"Federated identity","C":"Local account management","D":"Privileged access management"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Federated identity allows an organization to trust an external identity provider (IdP) for user authentication. Users authenticate with the IdP and the application trusts the IdP's assertion without managing its own credentials.","A":"On-premises authentication manages identities locally; federation uses a trusted external IdP.","B":"Correct. Trusting an external IdP for authentication is federated identity.","C":"Local account management means the application maintains its own user credentials.","D":"PAM manages privileged accounts; not web application authentication federation."}},
  {"id":313,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which email security record in DNS specifies which mail servers are authorized to send email for a domain?","options":{"A":"MX record","B":"DKIM","C":"SPF record","D":"DMARC"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"SPF (Sender Policy Framework) is a DNS TXT record that lists the IP addresses and mail servers authorized to send email on behalf of a domain, helping receivers detect spoofed senders.","A":"MX records specify which servers receive email for a domain; SPF specifies which can send.","B":"DKIM provides email signature verification using cryptographic keys; SPF specifies authorized senders.","C":"Correct. SPF lists authorized mail sending sources in a DNS TXT record.","D":"DMARC is a policy that uses SPF and DKIM results to determine how to handle failures."}},
  {"id":314,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which password security practice prevents users from reusing their last 10 passwords?","options":{"A":"Password complexity","B":"Password history","C":"Password expiration","D":"Minimum password length"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"Password history stores a record of previously used passwords and prevents users from reusing any of the last N passwords, forcing true password changes rather than password cycling.","A":"Password complexity requires certain character types; it doesn't prevent reuse.","B":"Correct. Password history prevents reuse of previously used passwords.","C":"Password expiration forces periodic changes; it doesn't specifically prevent reuse (history does).","D":"Minimum length requires a certain number of characters; doesn't prevent reuse."}},
  {"id":315,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"Which action BEST describes the eradication phase of incident response?","options":{"A":"Isolating infected systems from the network","B":"Removing malware, closing backdoors, and resetting compromised credentials","C":"Restoring systems from clean backups","D":"Documenting the incident timeline"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Eradication involves completely removing the threat: deleting malware, closing attacker backdoors, revoking compromised credentials, and eliminating the root cause.","A":"Isolating systems is containment, which occurs before eradication.","B":"Correct. Removing malware, closing backdoors, and resetting credentials is the eradication phase.","C":"Restoring from backups is the recovery phase after eradication.","D":"Documenting the timeline is part of detection/analysis and lessons learned."}},
  {"id":316,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which threat intelligence framework categorizes adversary behaviors using a matrix of tactics and techniques based on real-world observations?","options":{"A":"CVE","B":"CVSS","C":"MITRE ATT&CK","D":"CIS Controls"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"MITRE ATT&CK (Adversarial Tactics, Techniques, and Common Knowledge) is a matrix of real-world adversary behaviors organized by tactics (goals) and techniques (methods), used for threat modeling and detection.","A":"CVE is a database of publicly disclosed vulnerabilities; not an adversary behavior framework.","B":"CVSS is a vulnerability severity scoring system; not an adversary behavior framework.","C":"Correct. MITRE ATT&CK catalogs adversary tactics and techniques for threat analysis.","D":"CIS Controls is a set of security best practices; not an adversary behavior taxonomy."}},
  {"id":317,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which document issued by a software vendor provides information about a newly discovered vulnerability and available patches?","options":{"A":"CVE","B":"Security advisory","C":"CVSS score","D":"Penetration test report"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A security advisory is a vendor-published document that details a discovered vulnerability, its impact, affected versions, and available mitigations or patches.","A":"A CVE is a standardized vulnerability identifier assigned by MITRE; advisories reference CVEs.","B":"Correct. A security advisory communicates vulnerability details and remediation guidance from vendors.","C":"CVSS score rates vulnerability severity; it's included in advisories but is not itself an advisory.","D":"A penetration test report documents findings from a security assessment; it's not a vendor document."}},
  {"id":318,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which OS hardening technique removes or disables all software components not required for the system's intended function?","options":{"A":"Patch management","B":"Least functionality","C":"Encryption","D":"Log forwarding"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Least functionality configures a system with only the minimum required features, services, ports, and accounts, disabling or removing everything unnecessary to reduce the attack surface.","A":"Patch management updates software; least functionality removes unnecessary software.","B":"Correct. Least functionality removes unnecessary components to minimize attack surface.","C":"Encryption protects data; it doesn't involve removing unnecessary software.","D":"Log forwarding sends logs to a central server; unrelated to reducing installed components."}},
  {"id":319,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which monitoring approach captures packets off the network wire for later analysis without affecting live traffic?","options":{"A":"Inline IPS","B":"Network TAP (passive capture)","C":"SIEM correlation","D":"Host-based monitoring"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A network TAP (Test Access Point) creates a passive copy of network traffic for analysis tools without affecting the live traffic flow. It's commonly used for IDS sensors and packet capture.","A":"Inline IPS sits in the traffic path and actively filters traffic; network TAPs are passive.","B":"Correct. Network TAPs passively copy traffic for analysis without affecting production traffic.","C":"SIEM correlation analyzes logs; it doesn't directly capture network packets.","D":"Host-based monitoring runs on the endpoint; network TAPs monitor at the network level."}},
  {"id":320,"domain":4,"subdomain":"4.9","objective":"Use data sources to support an investigation","stem":"Which data source would an analyst consult to determine which external IP addresses a compromised host connected to over the past 30 days?","options":{"A":"Windows Security Event Log","B":"NetFlow/IPFIX records","C":"DHCP server logs","D":"Vulnerability scanner results"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"NetFlow/IPFIX records from routers and switches track connection data (source/destination IPs, ports, timestamps) over time, enabling analysts to reconstruct which external IPs a host communicated with.","A":"Windows Security Event Log records local authentication and system events; not network connections to external IPs.","B":"Correct. NetFlow/IPFIX records show historical network connections including source/destination IPs.","C":"DHCP logs record IP assignments; they show which IP a host was assigned but not its outbound connections.","D":"Vulnerability scanner results show vulnerabilities; not historical network connections."}},
  {"id":321,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which IAM concept grants access based on time-limited approval workflows rather than permanent permission assignments?","options":{"A":"RBAC","B":"ABAC","C":"Just-in-time (JIT) provisioning","D":"Federated identity"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Just-in-time provisioning grants access rights only when needed through an approval workflow, automatically revoking them after a defined period, reducing standing privileged access.","A":"RBAC assigns permanent role-based permissions; JIT is about temporary, on-demand access.","B":"ABAC uses attribute combinations for access decisions; JIT is specifically about temporality.","C":"Correct. JIT provisioning grants temporary access on demand, revoking it automatically.","D":"Federated identity uses external IdPs for authentication; not about access duration management."}},
  {"id":322,"domain":4,"subdomain":"4.7","objective":"Explain the importance of automation and orchestration","stem":"Which term describes a documented, automated set of steps for responding to a specific type of security incident?","options":{"A":"Runbook","B":"Policy","C":"Playbook","D":"Standard"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"A playbook is a documented set of steps and decision points for responding to a specific incident type. In SOAR, playbooks are automated and trigger specific response actions.","A":"A runbook is an operational procedure for routine tasks (not incident-specific); playbooks are specifically for incident response scenarios.","B":"A policy defines high-level requirements; not specific incident response steps.","C":"Correct. A playbook defines the steps for responding to a specific incident type, often automated in SOAR.","D":"A standard defines specific technical requirements; not incident response procedures."}},
  {"id":323,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"A forensic investigator writes all findings to a write-protected forensic image. Why is write protection important?","options":{"A":"To speed up the analysis process","B":"To prevent alteration of evidence, maintaining integrity","C":"To compress the image file size","D":"To encrypt the forensic image"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Write protection ensures that the forensic analysis does not modify the original evidence. All analysis is performed on copies, with the original preserved unaltered to maintain evidence integrity and admissibility.","A":"Write protection doesn't affect analysis speed.","B":"Correct. Write protection preserves evidence integrity by preventing unintentional modification.","C":"Forensic images are not compressed by write protection; they capture every bit.","D":"Encryption is a separate step for protecting the image in transit/storage; write protection prevents modification."}},
  {"id":324,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which authentication vulnerability occurs when an attacker captures a valid authentication token and submits it again later?","options":{"A":"Pass-the-hash","B":"Replay attack","C":"Kerberoasting","D":"Credential stuffing"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A replay attack captures a valid authentication token or message and retransmits it to authenticate as the legitimate user. Countermeasures include nonces, timestamps, and session tokens.","A":"Pass-the-hash specifically uses NTLM hashes; a replay attack is the broader category.","B":"Correct. Replay attacks retransmit captured authentication tokens to authenticate without credentials.","C":"Kerberoasting extracts Kerberos tickets for offline cracking; it's not about replaying tokens.","D":"Credential stuffing uses breach-obtained credentials; replay uses captured session tokens."}},
  {"id":325,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"NIST SP 800-88 provides guidelines for which security activity?","options":{"A":"Vulnerability scanning","B":"Media sanitization","C":"Incident response","D":"Penetration testing"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"NIST SP 800-88 'Guidelines for Media Sanitization' provides methods and recommendations for properly clearing, purging, and destroying storage media to prevent data recovery.","A":"Vulnerability scanning is addressed by other NIST publications; 800-88 is specifically about media sanitization.","B":"Correct. NIST SP 800-88 covers media sanitization (clearing, purging, destroying).","C":"Incident response is covered by NIST SP 800-61.","D":"Penetration testing guidance is in NIST SP 800-115."}},
  {"id":326,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which application security testing approach analyzes source code for vulnerabilities without executing it?","options":{"A":"DAST","B":"IAST","C":"SAST","D":"Fuzzing"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"SAST (Static Application Security Testing) analyzes source code, bytecode, or binaries for vulnerabilities without executing the application — often integrated into the CI/CD pipeline.","A":"DAST (Dynamic) tests running applications from outside; it doesn't analyze source code.","B":"IAST (Interactive) instruments running applications to detect vulnerabilities during execution.","C":"Correct. SAST analyzes code without execution (static analysis).","D":"Fuzzing sends random inputs to a running application; not static code analysis."}},
  {"id":327,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which metric measures the percentage of real threats correctly identified by a detection system?","options":{"A":"False positive rate","B":"False negative rate","C":"True positive rate (detection rate)","D":"Specificity"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"The true positive rate (detection rate or sensitivity) measures the percentage of actual threats that are correctly identified by the detection system. Higher is better.","A":"False positive rate measures legitimate events incorrectly flagged as threats.","B":"False negative rate measures real threats missed by the system — should be minimized.","C":"Correct. True positive rate measures the percentage of real threats correctly detected.","D":"Specificity measures the rate of correctly identified non-threats (true negatives)."}},
  {"id":328,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"Which IR activity immediately follows eradication to restore normal business operations?","options":{"A":"Containment","B":"Detection","C":"Recovery","D":"Lessons learned"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"After eradication removes the threat, recovery restores affected systems and services to normal operation, including restoring from backups, patching systems, and validating functionality.","A":"Containment precedes eradication; it comes before recovery.","B":"Detection occurs at the beginning of the IR lifecycle.","C":"Correct. Recovery follows eradication and restores systems to normal operation.","D":"Lessons learned is the final phase, conducted after recovery is complete."}},
  {"id":329,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which technique uses a separate, isolated environment to execute suspicious files and observe their behavior?","options":{"A":"Allowlisting","B":"Sandboxing","C":"Signature scanning","D":"Heuristic analysis"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Sandboxing executes suspicious files in an isolated, controlled environment (sandbox) where their behavior can be observed without risk to production systems. It's used for dynamic malware analysis.","A":"Allowlisting permits only approved applications; it doesn't analyze suspicious files.","B":"Correct. Sandboxing executes files in an isolated environment for behavioral analysis.","C":"Signature scanning matches files against known threat signatures; it doesn't execute or observe behavior.","D":"Heuristic analysis looks for suspicious code patterns without full execution; sandboxing provides full dynamic execution."}},
  {"id":330,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"A user's account is immediately disabled and badge access revoked upon resignation. This follows which security principle?","options":{"A":"Least privilege","B":"Separation of duties","C":"Timely deprovisioning","D":"Need-to-know"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Timely deprovisioning ensures that access is revoked promptly when an employee leaves to prevent former employees from retaining access to systems and data.","A":"Least privilege limits access scope; deprovisioning is about removing access entirely.","B":"Separation of duties divides tasks; not related to account termination.","C":"Correct. Immediately disabling accounts upon resignation is timely deprovisioning.","D":"Need-to-know restricts access based on relevance; deprovisioning removes it entirely."}},
  {"id":331,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which type of penetration test gives the tester no prior knowledge of the target environment?","options":{"A":"White box","B":"Gray box","C":"Black box","D":"Crystal box"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Black box testing simulates an external attacker with no prior knowledge of the target — the tester must enumerate and discover everything, mimicking a real-world attack scenario.","A":"White box testing provides full knowledge (architecture, code, credentials) for comprehensive testing.","B":"Gray box testing provides partial knowledge (some internal information) to the tester.","C":"Correct. Black box testing starts with zero knowledge of the target environment.","D":"Crystal box is another name for white box testing, not a standard term for zero-knowledge testing."}},
  {"id":332,"domain":4,"subdomain":"4.9","objective":"Use data sources to support an investigation","stem":"Which data source provides the MOST immediate insight into what processes are running and what network connections are active on a compromised host?","options":{"A":"Disk forensic image","B":"Log files","C":"Live memory (RAM) capture","D":"Network flow records"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Live RAM capture reveals running processes, active network connections, loaded DLLs, encryption keys, and other volatile artifacts that may not be present on disk or in logs.","A":"Disk images capture persistent data; volatile state like active processes requires RAM.","B":"Log files capture historical events; they don't show current state of running processes.","C":"Correct. Live memory capture reveals current running state including processes and connections.","D":"Network flow records show historical connections; RAM shows current active connections plus process context."}},
  {"id":333,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which security feature ensures that web browsers only connect to a site via HTTPS and never allow HTTP downgrade?","options":{"A":"Certificate pinning","B":"HSTS (HTTP Strict Transport Security)","C":"CSP (Content Security Policy)","D":"CORS"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"HSTS (HTTP Strict Transport Security) is a response header that instructs browsers to only connect to the site via HTTPS for a specified duration, preventing HTTP downgrade attacks like SSL stripping.","A":"Certificate pinning validates specific certificates; HSTS enforces HTTPS protocol usage.","B":"Correct. HSTS prevents HTTP connections by instructing browsers to use only HTTPS.","C":"CSP controls which resources a page can load; it doesn't enforce HTTPS transport.","D":"CORS controls cross-origin resource sharing; not related to protocol enforcement."}},
  {"id":334,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which FIDO2 component is a hardware device that stores cryptographic keys and performs authentication locally?","options":{"A":"Authenticator app","B":"Security key (hardware authenticator)","C":"Smart card","D":"Soft token"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"A FIDO2 hardware security key (like YubiKey) stores private keys in tamper-resistant hardware and performs cryptographic operations on-device. Private keys never leave the device.","A":"Authenticator apps implement TOTP; they're not FIDO2 hardware authenticators.","B":"Correct. A FIDO2 hardware security key stores keys in tamper-resistant hardware.","C":"Smart cards store certificates and can be FIDO2-compatible but are a separate category.","D":"Soft tokens are software-based OTP generators; not hardware FIDO2 authenticators."}},
  {"id":335,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which scanning technique probes a system from inside the network perimeter as if an authorized internal user or device?","options":{"A":"External scan","B":"Passive scan","C":"Internal scan","D":"Agent-based scan"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"An internal scan is conducted from within the network perimeter, simulating an insider threat or a compromised internal host. It finds vulnerabilities not visible from the outside.","A":"External scans simulate attacks from the internet, outside the perimeter.","B":"Passive scans observe network traffic without probing; they don't actively test systems.","C":"Correct. Internal scans probe from inside the network, simulating internal threats.","D":"Agent-based scans run software on the target; internal scan describes the network position of the scanner."}},
  {"id":336,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"An analyst is reviewing SIEM alerts and notices 1,000 alerts per day with only 10 being real threats. This alert volume problem is called:","options":{"A":"False negative fatigue","B":"Alert fatigue","C":"True positive overload","D":"Log flooding"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Alert fatigue occurs when security analysts are overwhelmed by large volumes of alerts (many false positives), causing them to miss real threats or reduce their review diligence.","A":"False negative fatigue isn't a standard term; missing real threats is the consequence of alert fatigue.","B":"Correct. High alert volume with mostly false positives causes alert fatigue.","C":"True positive overload would mean all alerts are real — valuable but not the described problem.","D":"Log flooding is a DoS attack technique on logging systems; not the same as alert fatigue."}},
  {"id":337,"domain":4,"subdomain":"4.7","objective":"Explain the importance of automation and orchestration","stem":"Which caveat of security automation should be considered before removing all human oversight?","options":{"A":"Automation always improves security outcomes","B":"Automation can introduce new vulnerabilities and may make incorrect decisions","C":"Automation eliminates the need for security policies","D":"Automated systems never generate false positives"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Automation can make incorrect decisions based on flawed rules or unexpected conditions, potentially blocking legitimate traffic or missing novel threats. Human oversight remains essential for complex decisions.","A":"Automation improves efficiency but can introduce misconfiguration risks and logic errors.","B":"Correct. Automation has limitations — it can make incorrect decisions and may introduce new risks.","C":"Security policies are more important with automation to define what should be automated.","D":"Automated systems can generate false positives, potentially disrupting business operations."}},
  {"id":338,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"An IR team discovers the attacker used a zero-day vulnerability. Which FIRST action should they take?","options":{"A":"Patch the vulnerability","B":"Contain the incident by isolating affected systems","C":"Notify law enforcement","D":"Restore from backup"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"The immediate priority in any incident is containment — stopping the spread of the attack before eradication and recovery. Even with a zero-day, containment (isolation) is the first action.","A":"Patching may not be immediately possible for a zero-day (no patch exists); containment is first.","B":"Correct. Containment is always the first active response to limit damage spread.","C":"Notifying law enforcement may be required but follows initial containment actions.","D":"Restoration from backup is the recovery phase, which comes after containment and eradication."}},
  {"id":339,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which endpoint security technology uses machine learning to detect malware based on behavior rather than signatures?","options":{"A":"Legacy AV (signature-based)","B":"EDR with ML behavioral analysis","C":"FIM","D":"NAC"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Modern EDR solutions use machine learning to analyze endpoint behavior patterns, detecting malware and threats that don't match known signatures, including fileless malware and zero-days.","A":"Legacy AV relies on signature databases; it misses novel, unknown malware.","B":"Correct. EDR with ML detects threats based on behavioral patterns rather than signatures.","C":"FIM detects unauthorized file changes; it doesn't analyze behavioral patterns for malware.","D":"NAC controls network access based on device compliance; it doesn't detect malware behavior."}},
  {"id":340,"domain":4,"subdomain":"4.9","objective":"Use data sources to support an investigation","stem":"Which data source would show a complete history of a user's web browsing activity on a corporate network?","options":{"A":"DHCP logs","B":"Web proxy logs","C":"DNS logs","D":"Firewall logs"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Web proxy logs record every URL requested through the proxy including timestamps, user identity, URLs, and response codes — providing complete browsing history for corporate users.","A":"DHCP logs record IP assignments; they identify the device but not browsing activity.","B":"Correct. Web proxy logs provide complete URL-level browsing history with user identity.","C":"DNS logs show domain lookups but not specific URLs; the proxy provides URL-level detail.","D":"Firewall logs show network connections (IP/port); they don't capture URL-level detail."}},
  {"id":341,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which network device configuration isolates different tenant traffic in a shared infrastructure by using numeric identifiers for each isolated domain?","options":{"A":"ACL","B":"VLAN","C":"VPN","D":"Firewall zone"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"VLANs (Virtual LANs) use VLAN IDs to logically separate traffic on the same physical infrastructure, isolating different groups or tenants from each other at Layer 2.","A":"ACLs filter traffic between networks; VLANs create the logical separation itself.","B":"Correct. VLANs use VLAN IDs to logically isolate network segments on shared infrastructure.","C":"VPNs create encrypted tunnels; they don't provide Layer 2 segmentation on local infrastructure.","D":"Firewall zones are logical groupings for policy enforcement, not the isolation mechanism itself."}},
  {"id":342,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"An organization is unable to patch a critical server immediately. Which compensating control BEST reduces risk in the interim?","options":{"A":"Add more memory to the server","B":"Enable additional firewall rules to limit access to the vulnerable service","C":"Update the server's hostname","D":"Increase backup frequency"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Adding restrictive firewall rules limits which systems can reach the vulnerable service, reducing the number of potential attack sources while the patch is being prepared and tested.","A":"Adding memory does not address a vulnerability.","B":"Correct. Restricting network access to the vulnerable service limits exposure until patching.","C":"Changing the hostname doesn't address the vulnerability.","D":"Increased backups help with recovery but don't reduce the likelihood of exploitation."}},
  {"id":343,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which type of authentication does Windows Hello for Business use, making it resistant to phishing attacks?","options":{"A":"Password-based with MFA","B":"FIDO2 public key cryptography","C":"Kerberos with certificate pinning","D":"TOTP soft token"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Windows Hello for Business uses FIDO2/WebAuthn public key cryptography — the private key never leaves the device and credentials are biometrically protected, making it phishing-resistant.","A":"Passwords can be phished; FIDO2 authenticators cannot be.","B":"Correct. Windows Hello for Business uses FIDO2 public key cryptography, which is phishing-resistant.","C":"Kerberos is used internally but Windows Hello uses public key cryptography for the authentication factor.","D":"TOTP codes can be phished in real-time; FIDO2 is phishing-resistant."}},
  {"id":344,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which type of threat intelligence sharing uses standardized formats (STIX/TAXII) to automate the exchange of threat indicators between organizations?","options":{"A":"Manual IOC sharing","B":"ISAC participation","C":"Automated threat intelligence feeds","D":"Security advisory subscriptions"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Automated threat intelligence feeds use standards like STIX (Structured Threat Information Expression) for data format and TAXII (Trusted Automated Exchange of Intelligence Information) for transport, enabling automated IOC exchange.","A":"Manual IOC sharing is slow and doesn't use standardized machine-readable formats.","B":"ISACs share threat intelligence for specific sectors; automated feeds use STIX/TAXII for automation.","C":"Correct. Automated feeds using STIX/TAXII enable machine-speed threat indicator exchange.","D":"Security advisory subscriptions provide human-readable notifications; not automated IOC exchange."}},
  {"id":345,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"A forensic analyst collects a disk image and immediately computes its MD5 and SHA-256 hashes. What is the purpose?","options":{"A":"To encrypt the image for secure storage","B":"To verify the image integrity and detect any future tampering","C":"To compress the image file","D":"To identify the OS on the disk"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Computing cryptographic hashes of a forensic image immediately after collection creates a baseline. Any future modification to the image will produce a different hash, detecting tampering and verifying integrity.","A":"Hashing is not encryption; it doesn't protect confidentiality of the image.","B":"Correct. Hashing the image creates an integrity baseline to detect any future tampering.","C":"Hashing doesn't compress files.","D":"OS identification requires examining the image contents; hashing only verifies integrity."}},
  {"id":346,"domain":4,"subdomain":"4.7","objective":"Explain the importance of automation and orchestration","stem":"Which activity is MOST appropriate for security automation in a SOC environment?","options":{"A":"Determining if a novel APT campaign is ongoing","B":"Enriching alerts with threat intelligence and creating tickets automatically","C":"Making strategic risk management decisions","D":"Negotiating with ransomware operators"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Alert enrichment (adding context like IP reputation, file hash info, user history) and ticket creation are repetitive, rule-based tasks that are ideal for automation, freeing analysts for complex investigation.","A":"APT campaign determination requires human analysis and judgment; automation can assist but not decide.","B":"Correct. Alert enrichment and ticket creation are repetitive tasks ideal for automation.","C":"Strategic risk decisions require human judgment and organizational context.","D":"Negotiation requires human judgment and is not appropriate for automation."}},
  {"id":347,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"A company accepts a known vulnerability because the cost of remediation exceeds the value of the asset at risk. This is an example of:","options":{"A":"Risk avoidance","B":"Risk transference","C":"Risk acceptance","D":"Risk mitigation"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Risk acceptance is the conscious decision to tolerate a known risk, typically when the cost of remediation exceeds the potential loss or when the risk is within the organization's tolerance.","A":"Risk avoidance eliminates the activity or asset that creates the risk.","B":"Risk transference shifts the risk to a third party (insurance, vendor contracts).","C":"Correct. Accepting a known vulnerability because remediation cost exceeds risk is risk acceptance.","D":"Risk mitigation reduces the likelihood or impact of a risk; acceptance does nothing to change it."}},
  {"id":348,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which web application security header prevents a page from being loaded in an iframe on another domain, protecting against clickjacking?","options":{"A":"Content-Security-Policy","B":"X-Frame-Options","C":"HSTS","D":"X-XSS-Protection"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"The X-Frame-Options (or frame-ancestors in CSP) header prevents a page from being embedded in iframes on other domains, directly mitigating clickjacking attacks.","A":"CSP can restrict framing via frame-ancestors directive, but X-Frame-Options is the specific header traditionally used.","B":"Correct. X-Frame-Options prevents the page from being framed by external domains.","C":"HSTS enforces HTTPS; it doesn't control framing.","D":"X-XSS-Protection is a legacy header for XSS filtering; not related to clickjacking."}},
  {"id":349,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which log source is MOST useful for detecting data exfiltration attempts over email?","options":{"A":"Windows Security Event Log","B":"Firewall logs","C":"Email gateway/MTA logs","D":"DHCP logs"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Email gateway (MTA) logs record all sent and received messages, attachment types, recipient addresses, and message sizes — enabling detection of large attachments sent to external addresses or unusual recipient patterns.","A":"Windows Security Event Logs record authentication/system events; not email content.","B":"Firewall logs show network connections; they don't show email content or attachment details.","C":"Correct. Email gateway logs provide details on sent messages, attachments, and recipients.","D":"DHCP logs record IP assignments; not email activity."}},
  {"id":350,"domain":4,"subdomain":"4.9","objective":"Use data sources to support an investigation","stem":"Which indicator type consists of specific technical artifacts like IP addresses, domain names, file hashes, and registry keys associated with known threats?","options":{"A":"TTP (Tactics, Techniques, Procedures)","B":"IOC (Indicators of Compromise)","C":"CVE","D":"CVSS"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"IOCs (Indicators of Compromise) are specific technical artifacts that indicate a system has been compromised — including IP addresses, domain names, file hashes, email addresses, and registry keys.","A":"TTPs describe adversary behavior patterns (more strategic); IOCs are specific technical artifacts.","B":"Correct. IOCs are technical artifacts like IPs, hashes, and domains that indicate compromise.","C":"CVE identifies software vulnerabilities; not threat artifacts on a compromised system.","D":"CVSS scores vulnerability severity; not compromise indicators."}},
  {"id":351,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which Linux command would an administrator use to view currently running processes and identify unusual ones?","options":{"A":"ls","B":"ps aux or top","C":"netstat","D":"grep"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"'ps aux' lists all running processes with details; 'top' provides a real-time view. These commands help identify unusual processes that might indicate malware.","A":"'ls' lists directory contents; it doesn't show running processes.","B":"Correct. 'ps aux' and 'top' display running processes for investigation.","C":"'netstat' shows network connections; useful but doesn't show processes without -p flag.","D":"'grep' searches text; it doesn't list processes by itself."}},
  {"id":352,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which concept requires that at least two people must authorize certain critical transactions or changes?","options":{"A":"Least privilege","B":"Dual control / two-person integrity","C":"Separation of duties","D":"Job rotation"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Dual control (two-person integrity) requires that two authorized people must be present and agree before a critical action can be performed — neither person can complete it alone.","A":"Least privilege limits access scope; dual control requires two people for a single action.","B":"Correct. Dual control requires two authorized people to complete a critical action.","C":"Separation of duties splits a process across multiple people; dual control requires both present for a single action.","D":"Job rotation moves employees between roles to prevent fraud; not about two-person authorization."}},
  {"id":353,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"Which notification requirement may exist when a breach involves personal data of EU residents?","options":{"A":"Notify affected users within 10 days","B":"Notify the supervisory authority within 72 hours under GDPR","C":"No notification required if data was encrypted","D":"Only notify if financial data was stolen"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"GDPR Article 33 requires notification to the relevant supervisory authority within 72 hours of becoming aware of a personal data breach. Article 34 requires notification to affected individuals for high-risk breaches.","A":"GDPR requires 72-hour notification to authorities, not 10 days.","B":"Correct. GDPR requires supervisory authority notification within 72 hours of awareness.","C":"Encryption may affect the notification to individuals but doesn't eliminate the authority notification requirement.","D":"GDPR covers all personal data, not just financial data."}},
  {"id":354,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"An attack surface management tool continuously discovers internet-facing assets of an organization. This is MOST useful for:","options":{"A":"Internal network monitoring","B":"Identifying unknown or unmanaged external assets and vulnerabilities","C":"Monitoring employee activity","D":"Patch deployment"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Attack surface management (ASM) continuously discovers and monitors an organization's external-facing assets — including forgotten systems, cloud assets, and subsidiaries — identifying unknown risks.","A":"ASM focuses on external internet-facing assets; internal monitoring uses different tools.","B":"Correct. ASM identifies unknown external assets and vulnerabilities that security teams may not know exist.","C":"Employee activity monitoring uses UEBA and DLP tools.","D":"Patch deployment is a remediation action after vulnerabilities are identified."}},
  {"id":355,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"A company implements a proxy that decrypts HTTPS traffic, checks it against URL categorization and threat databases, then re-encrypts it. This is called:","options":{"A":"Forward proxy with SSL inspection","B":"Reverse proxy","C":"Transparent proxy","D":"SOCKS proxy"},"correct_answer":"A","difficulty":3,"explanations":{"correct":"A forward proxy with SSL/TLS inspection intercepts outbound HTTPS connections, decrypts them for inspection (URL filtering, threat scanning), and re-encrypts before forwarding to the destination.","A":"Correct. A forward proxy with SSL inspection decrypts, inspects, and re-encrypts outbound HTTPS traffic.","B":"A reverse proxy handles inbound requests on behalf of servers; forward proxies handle outbound client requests.","C":"A transparent proxy intercepts traffic without client configuration but this specifically describes inspection capability.","D":"A SOCKS proxy tunnels TCP connections without content inspection."}},
  {"id":356,"domain":4,"subdomain":"4.9","objective":"Use data sources to support an investigation","stem":"An investigator needs to determine which user account made changes to a critical configuration file on a Linux server. Which log source is MOST useful?","options":{"A":"Application logs","B":"/var/log/auth.log and auditd logs","C":"Network flow records","D":"DNS logs"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Linux auth.log records authentication events and sudo usage, while auditd logs track file access and modification events when file auditing rules are configured — together showing who made changes.","A":"Application logs record application-specific events; configuration file changes are system-level.","B":"Correct. auth.log and auditd logs record authentication and file access/modification events on Linux.","C":"Network flow records show network connections; not local file modifications.","D":"DNS logs show name resolution; not local system file changes."}},
  {"id":357,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which access control concept ensures a user cannot approve their own expense report?","options":{"A":"Least privilege","B":"Need-to-know","C":"Separation of duties","D":"Mandatory access control"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Separation of duties requires that no single person controls all steps of a critical process. Requiring a different person to approve expense reports prevents self-approval fraud.","A":"Least privilege limits access rights but doesn't specifically address who approves vs. who submits.","B":"Need-to-know restricts information access; it doesn't address approval workflows.","C":"Correct. Separation of duties prevents one person from submitting AND approving their own transactions.","D":"MAC enforces access via security labels; not specifically about workflow separation."}},
  {"id":358,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which security capability uses machine learning to detect anomalous user behavior such as logging in from an unusual country?","options":{"A":"SIEM rule-based correlation","B":"UEBA (User and Entity Behavior Analytics)","C":"NAC","D":"DLP"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"UEBA uses machine learning to establish behavioral baselines for users and entities, alerting when activity deviates significantly — like login from an unusual geographic location or data access at odd hours.","A":"SIEM rule-based correlation uses predefined rules; UEBA uses ML for adaptive baselines.","B":"Correct. UEBA detects anomalous user behavior using machine learning baselines.","C":"NAC controls device access compliance; it doesn't analyze user behavioral patterns.","D":"DLP prevents data exfiltration; it doesn't detect behavioral anomalies like geographic location changes."}},
  {"id":359,"domain":4,"subdomain":"4.2","objective":"Explain the security implications of proper hardware, software, and data asset management","stem":"Which standard defines requirements for asset classification and handling in information security management systems?","options":{"A":"ISO 27001","B":"PCI DSS","C":"NIST SP 800-53","D":"COBIT"},"correct_answer":"A","difficulty":3,"explanations":{"correct":"ISO 27001 is the international standard for Information Security Management Systems (ISMS) and includes Annex A controls covering asset management, classification, and handling requirements.","A":"Correct. ISO 27001 includes asset classification and handling in its control framework.","B":"PCI DSS focuses on payment card data security; not a general asset management standard.","C":"NIST SP 800-53 is a US federal security control catalog; ISO 27001 is the international standard for ISMS.","D":"COBIT is an IT governance framework; ISO 27001 is specifically the security management standard."}},
  {"id":360,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which host-based control monitors and controls application interactions with the operating system to prevent malicious behavior?","options":{"A":"Firewall","B":"IPS","C":"Host-based IPS (HIPS) / Application control","D":"Network segmentation"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"HIPS and application control monitor application interactions at the OS level, detecting and blocking suspicious API calls, privilege escalation attempts, and abnormal application behavior.","A":"A firewall controls network traffic; it doesn't monitor application-OS interactions.","B":"Network IPS monitors network traffic; HIPS monitors host-level application behavior.","C":"Correct. HIPS/application control monitors and restricts how applications interact with the OS.","D":"Network segmentation limits network access between zones; it doesn't monitor application behavior."}},
  {"id":361,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which security monitoring technique records keyboard input, screen output, and commands executed during a privileged user session for audit?","options":{"A":"SIEM logging","B":"Session recording (PAM session monitoring)","C":"Network packet capture","D":"Event correlation"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Session recording captures the full content of privileged user sessions (keystrokes, screen, commands) for audit and investigation purposes, often implemented within PAM solutions.","A":"SIEM logging aggregates event data; it doesn't capture full session content.","B":"Correct. Session recording captures full privileged session content for audit.","C":"Network packet capture captures network traffic; not the full UI/console session.","D":"Event correlation analyzes log data relationships; it doesn't record session content."}},
  {"id":362,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which vulnerability management concept measures how often a threat actor successfully exploits a specific vulnerability?","options":{"A":"CVSS exploitability score","B":"EPSS (Exploit Prediction Scoring System)","C":"CVE count","D":"Patch Tuesday frequency"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"EPSS (Exploit Prediction Scoring System) uses machine learning to predict the probability that a CVE will be exploited in the wild in the next 30 days, helping prioritize remediation.","A":"CVSS exploitability measures technical ease of exploitation; EPSS predicts actual exploitation probability.","B":"Correct. EPSS predicts the probability of real-world exploitation for prioritization.","C":"CVE count is the number of vulnerabilities; it doesn't measure exploitation likelihood.","D":"Patch Tuesday is Microsoft's regular patch release cycle; not a vulnerability metric."}},
  {"id":363,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"During an IR investigation, analysts must NOT make changes to a live system before documenting and capturing its current state. This principle is called:","options":{"A":"Least privilege","B":"Preservation of evidence","C":"Chain of custody","D":"Legal hold"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Preservation of evidence requires capturing the current state of systems before any remediation actions, ensuring forensic evidence is not altered or destroyed during the investigation.","A":"Least privilege restricts access rights; not a forensic preservation principle.","B":"Correct. Preservation of evidence means capturing system state before making changes.","C":"Chain of custody tracks who handled evidence; preservation is about capturing it unchanged.","D":"Legal hold preserves records relevant to litigation; evidence preservation is about capturing system state."}},
  {"id":364,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"An organization deploys certificates to all company devices so that only managed devices can connect to Wi-Fi. This uses which protocol?","options":{"A":"WPA2-Personal","B":"802.1X with EAP-TLS","C":"WPS","D":"WEP"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"802.1X with EAP-TLS uses client certificates for Wi-Fi authentication. Only devices with valid, company-issued certificates can authenticate, enforcing managed device access.","A":"WPA2-Personal uses a shared passphrase, not certificates.","B":"Correct. 802.1X with EAP-TLS authenticates devices using certificates, ensuring only managed devices connect.","C":"WPS is a vulnerable convenience feature; it doesn't use certificates.","D":"WEP is deprecated and broken; not used for certificate-based authentication."}},
  {"id":365,"domain":4,"subdomain":"4.9","objective":"Use data sources to support an investigation","stem":"An analyst uses a threat intelligence platform to look up an IP address associated with suspicious traffic. Which information would MOST help determine if the IP is malicious?","options":{"A":"WHOIS registration date","B":"Geolocation data","C":"Threat reputation score and historical malicious activity","D":"ISP name"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"A threat reputation score aggregates historical data on whether the IP has been associated with malicious activity (C2, spam, scanning, malware), providing the most direct evidence of whether it is malicious.","A":"Registration date provides some context but doesn't directly indicate malicious use.","B":"Geolocation identifies country but many legitimate IPs originate from the same countries as attacks.","C":"Correct. Reputation scores and historical malicious activity are the most direct indicators of maliciousness.","D":"ISP name provides context but many malicious IPs use legitimate ISPs (including cloud providers)."}},
  {"id":366,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which account type should be used for running system services that need elevated access, configured with minimal privileges and a long, complex password?","options":{"A":"User account","B":"Service account","C":"Guest account","D":"Administrator account"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Service accounts are dedicated accounts for running system services. They should be configured with least privilege (only what the service needs), complex passwords, and no interactive logon rights.","A":"User accounts are for human users; service accounts are dedicated to running services.","B":"Correct. Service accounts run system services with appropriate, limited privileges.","C":"Guest accounts are for temporary, limited access; not appropriate for services.","D":"Administrator accounts have full system privileges; services should use least-privilege service accounts."}},
  {"id":367,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which baseline security configuration is established by organizations like CIS as a starting point for secure system deployment?","options":{"A":"Vulnerability scan","B":"Security benchmark / hardening guide","C":"Penetration test report","D":"Risk assessment"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"CIS Benchmarks and similar hardening guides provide prescriptive security configuration baselines for operating systems and applications, establishing secure configuration starting points.","A":"A vulnerability scan identifies vulnerabilities; benchmarks define secure configurations.","B":"Correct. Security benchmarks (like CIS Benchmarks) are hardening baselines for secure configuration.","C":"Penetration test reports identify vulnerabilities found during testing; not configuration baselines.","D":"Risk assessments evaluate risks; not configuration baselines."}},
  {"id":368,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"After vulnerability scanning, a finding of 'CVE-2023-XXXX: Apache Log4j RCE — Severity: Critical' requires urgent attention. What is the FIRST step?","options":{"A":"Accept the risk and document it","B":"Confirm the vulnerability exists and assess affected systems","C":"Immediately notify all employees","D":"Shut down all Apache servers"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Before taking remediation action, analysts must confirm the vulnerability actually exists on the system (not a false positive) and identify all affected systems to determine the full scope.","A":"Risk acceptance is appropriate after analysis reveals patching is not feasible; not the first step for a critical RCE.","B":"Correct. Confirm the finding and assess scope before taking remediation action.","C":"Employee notification may be required for some incidents but is not the first technical step.","D":"Shutting down all servers without confirmation of impact is disproportionate and disruptive."}},
  {"id":369,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which security tool specifically designed for web applications can detect SQL injection, XSS, and other OWASP Top 10 vulnerabilities in real time?","options":{"A":"Network IPS","B":"WAF (Web Application Firewall)","C":"NGFW","D":"Load balancer"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A WAF (Web Application Firewall) specifically inspects HTTP/HTTPS traffic at the application layer, detecting and blocking OWASP Top 10 attacks like SQL injection, XSS, and CSRF.","A":"Network IPS inspects general network traffic but lacks web application-specific rules for OWASP Top 10.","B":"Correct. A WAF is specifically designed to detect and block web application attacks.","C":"NGFW includes some WAF capabilities but a dedicated WAF provides more comprehensive web application protection.","D":"Load balancers distribute traffic; they don't inspect for web application attacks."}},
  {"id":370,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which log source would reveal that a previously authorized user account was used at 3:00 AM from an unusual IP after that user's working hours?","options":{"A":"Application log","B":"Authentication log / SIEM correlation","C":"Firewall log","D":"DNS log"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Authentication logs record login events with timestamps and source IPs. SIEM correlation can flag after-hours logins from unusual IPs as anomalous, enabling detection of compromised credentials.","A":"Application logs record application-level events; authentication events are in auth logs.","B":"Correct. Authentication logs and SIEM correlation reveal unusual login times and source IPs.","C":"Firewall logs show network connections; they show IPs but typically don't correlate with user identity.","D":"DNS logs show name resolution; they don't record authentication events."}},
  {"id":371,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"An organization's IR plan includes clear instructions for when to involve law enforcement. This is part of which IR planning element?","options":{"A":"Communication plan","B":"Legal and regulatory compliance","C":"Containment procedures","D":"Recovery procedures"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"The legal and regulatory compliance element of IR planning identifies when law enforcement notification is required (for certain breach types) and defines the process for involving authorities.","A":"Communication plans address internal and external communications; law enforcement involvement is a legal requirement element.","B":"Correct. Law enforcement notification procedures are part of legal and regulatory compliance in IR planning.","C":"Containment procedures isolate affected systems; they don't address law enforcement involvement.","D":"Recovery procedures restore systems; not about legal notification requirements."}},
  {"id":372,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which IAM best practice prevents credential theft by using cryptographic attestation instead of passwords for web authentication?","options":{"A":"Multi-factor authentication with TOTP","B":"Passwordless authentication with FIDO2/WebAuthn","C":"Certificate-based VPN authentication","D":"SSO with SAML"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"FIDO2/WebAuthn enables passwordless authentication using public key cryptography — the private key stays on the user's device and is used to sign a challenge, eliminating passwords that can be stolen or phished.","A":"TOTP is a second factor; FIDO2 can eliminate the password entirely.","B":"Correct. FIDO2/WebAuthn provides phishing-resistant passwordless authentication via public key cryptography.","C":"Certificate-based VPN replaces passwords for VPN access; FIDO2 is specifically for web authentication.","D":"SSO reduces how often users authenticate; FIDO2 changes the authentication mechanism to be passwordless."}},
  {"id":373,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which organization maintains the National Vulnerability Database (NVD) that provides CVSS scores for known vulnerabilities?","options":{"A":"MITRE","B":"NIST","C":"SANS Institute","D":"ISC2"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"NIST (National Institute of Standards and Technology) maintains the National Vulnerability Database (NVD), which provides CVSS scores, detailed vulnerability descriptions, and remediation information for CVEs.","A":"MITRE assigns CVE identifiers and maintains the CVE list; NIST maintains the NVD that enriches CVEs.","B":"Correct. NIST maintains the NVD with CVSS scores for documented vulnerabilities.","C":"SANS Institute provides security training and research; not the NVD.","D":"ISC2 is a professional certification organization; not related to vulnerability databases."}},
  {"id":374,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which concept involves establishing a known-good state of system files and configurations for comparison during investigations?","options":{"A":"Threat modeling","B":"Baseline configuration","C":"Risk register","D":"Threat hunting"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A baseline configuration (or security baseline) documents the known-good state of a system, enabling detection of unauthorized changes by comparing current state to the baseline.","A":"Threat modeling identifies potential threats; not about documenting known-good state.","B":"Correct. A baseline documents the known-good state for comparison and change detection.","C":"A risk register documents identified risks; not system configuration states.","D":"Threat hunting proactively searches for threats; baselines are used as reference points."}},
  {"id":375,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which hardening action specifically prevents an attacker from booting a laptop from a USB drive to bypass OS security?","options":{"A":"BitLocker","B":"BIOS/UEFI password and disabling USB boot","C":"AppLocker","D":"ASLR"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Setting a BIOS/UEFI password and changing the boot order to prevent booting from USB drives prevents attackers from bypassing the OS security by loading a different OS from removable media.","A":"BitLocker encrypts the drive but doesn't prevent booting from USB (though it protects data).","B":"Correct. BIOS/UEFI password protection and disabling USB boot prevents alternative boot methods.","C":"AppLocker controls application execution within the OS; it doesn't prevent alternative boot methods.","D":"ASLR randomizes memory addresses; it doesn't control boot methods."}},
  {"id":376,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"Which preparedness document outlines the roles, responsibilities, and procedures for responding to specific incident types before they occur?","options":{"A":"Risk assessment","B":"Business impact analysis","C":"Incident response plan","D":"Security policy"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"An incident response plan (IRP) pre-documents the procedures, roles, responsibilities, and communication chains for responding to security incidents, enabling faster and more effective response.","A":"A risk assessment identifies and evaluates risks; it doesn't define response procedures.","B":"BIA identifies critical functions and recovery priorities; the IRP defines response procedures.","C":"Correct. The incident response plan pre-documents response procedures, roles, and responsibilities.","D":"Security policy defines high-level requirements; the IRP provides specific procedural guidance."}},
  {"id":377,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"A company implements a policy that all endpoints must have a current AV signature file and OS patches before connecting to the corporate network. This is enforced by:","options":{"A":"IPS","B":"SIEM","C":"NAC (Network Access Control)","D":"DLP"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"NAC enforces health policies at network connection time. Endpoints that fail compliance checks (missing patches, outdated AV) are quarantined or denied access until they meet requirements.","A":"IPS detects and blocks attacks in transit; it doesn't assess endpoint health before connection.","B":"SIEM aggregates and correlates logs; it doesn't enforce endpoint health for network access.","C":"Correct. NAC enforces endpoint health requirements as a condition of network access.","D":"DLP prevents data exfiltration; it doesn't enforce endpoint compliance for network access."}},
  {"id":378,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"An identity management system uses SCIM (System for Cross-domain Identity Management) to automatically create and delete user accounts in multiple SaaS apps. This is:","options":{"A":"Federated SSO","B":"Automated provisioning/deprovisioning","C":"Role-based access control","D":"Privileged access management"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"SCIM automates the creation, update, and deletion of user accounts across multiple systems when changes occur in the authoritative identity source, enabling automated provisioning and deprovisioning.","A":"Federated SSO allows users to authenticate once across services; SCIM handles account lifecycle management.","B":"Correct. SCIM enables automated account provisioning and deprovisioning across SaaS applications.","C":"RBAC defines permission assignment by role; SCIM handles account lifecycle.","D":"PAM manages privileged accounts; SCIM handles general user account lifecycle."}},
  {"id":379,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which remediation action is appropriate when a critical vulnerability cannot be immediately patched due to operational constraints?","options":{"A":"Risk avoidance","B":"Compensating control implementation","C":"Vulnerability acceptance permanently","D":"Removing the system from inventory"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"When immediate patching is not feasible, compensating controls (network isolation, additional monitoring, WAF rules, disabling vulnerable features) reduce risk until the patch can be applied.","A":"Risk avoidance eliminates the asset or activity; not always feasible for critical systems.","B":"Correct. Compensating controls reduce risk when immediate patching is not possible.","C":"Permanent acceptance of a critical vulnerability is inappropriate without compensating controls and documented approval.","D":"Removing the system from inventory doesn't resolve the vulnerability or protect the system."}},
  {"id":380,"domain":4,"subdomain":"4.9","objective":"Use data sources to support an investigation","stem":"When investigating a web server breach, which log file reveals specific HTTP request paths, user agents, and source IPs of requests made to the server?","options":{"A":"System event log","B":"Web server access log (Apache/Nginx)","C":"DHCP log","D":"Firewall log"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Web server access logs record every HTTP request including the requested URL/path, HTTP method, source IP, user agent string, and response code — essential for investigating web-based attacks.","A":"System event logs record OS-level events; not HTTP request details.","B":"Correct. Web server access logs contain HTTP request details including paths, IPs, and user agents.","C":"DHCP logs record IP assignments; not HTTP requests.","D":"Firewall logs show network connections (IP/port); they don't contain HTTP request paths or user agents."}},
  {"id":381,"domain":4,"subdomain":"4.7","objective":"Explain the importance of automation and orchestration","stem":"Which concept allows security teams to define infrastructure and security controls as code, enabling consistent, repeatable deployment?","options":{"A":"DevSecOps","B":"Infrastructure as Code (IaC)","C":"Continuous integration","D":"Agile security"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Infrastructure as Code (IaC) defines infrastructure configurations in code (Terraform, Ansible, CloudFormation), enabling consistent, version-controlled, repeatable deployments with security controls embedded.","A":"DevSecOps integrates security into DevOps pipelines; IaC is a specific tool within this approach.","B":"Correct. IaC defines infrastructure as version-controlled code for consistent, repeatable deployment.","C":"Continuous integration automates code building and testing; IaC is about infrastructure provisioning.","D":"Agile security is a methodology; IaC is a specific practice."}},
  {"id":382,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"After a ransomware attack, the recovery team restores systems from offline backups and resets all credentials. What MUST be done before returning systems to production?","options":{"A":"Pay the ransom to get the decryption key","B":"Verify the restored systems are clean and free of the ransomware","C":"Delete all backup copies","D":"Disable all antivirus to speed up restoration"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Before returning restored systems to production, they must be verified to be free of malware. Restoring from an infected backup or returning an incompletely cleaned system could re-infect the environment.","A":"Paying ransom does not guarantee clean systems and funds criminal activity.","B":"Correct. Restored systems must be verified clean before returning to production.","C":"Backup copies should be preserved; they are needed for future recovery.","D":"Disabling AV during restoration increases the risk of missing malware; it should remain active."}},
  {"id":383,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which configuration change would BEST prevent credential brute-force attacks on a web application login?","options":{"A":"Increase password complexity requirements","B":"Implement CAPTCHA and account lockout after failed attempts","C":"Use HTTP instead of HTTPS","D":"Disable TLS certificate validation"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"CAPTCHA prevents automated brute-force attempts, and account lockout after N failures limits the number of attempts an attacker can make, together significantly reducing brute-force effectiveness.","A":"Complexity makes passwords harder to guess but doesn't limit automated brute-force attempt rate.","B":"Correct. CAPTCHA blocks automated attempts; account lockout limits total failed attempts.","C":"Using HTTP exposes credentials in transit — worse for security, not better.","D":"Disabling certificate validation enables MITM attacks — severely reduces security."}},
  {"id":384,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which type of threat feed provides real-time data about currently active malicious IPs and domains being used for C2?","options":{"A":"Static OSINT report","B":"Commercial threat intelligence feed","C":"Historical vulnerability database","D":"CVE list"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Commercial threat intelligence feeds provide continuously updated, real-time data on active threats including current C2 IPs, malicious domains, and active malware campaign indicators.","A":"Static OSINT reports are point-in-time; they don't provide real-time C2 data.","B":"Correct. Commercial threat intelligence feeds provide real-time, continuously updated threat data.","C":"Historical vulnerability databases list past vulnerabilities; not real-time C2 indicators.","D":"The CVE list catalogs disclosed vulnerabilities; not active threat indicators."}},
  {"id":385,"domain":4,"subdomain":"4.2","objective":"Explain the security implications of proper hardware, software, and data asset management","stem":"An organization's MDM solution uses a containerized work profile to separate business and personal apps on a BYOD device. Which concept does this implement?","options":{"A":"Full disk encryption","B":"Containerization / Workspace isolation","C":"Remote wipe","D":"Application allowlisting"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Workspace isolation (containerization) separates the work environment from the personal environment on BYOD devices, allowing IT to manage and wipe only the work container without touching personal data.","A":"Full disk encryption protects all data on the device but doesn't separate work and personal contexts.","B":"Correct. Work profile containerization separates work and personal environments on BYOD devices.","C":"Remote wipe erases the device (or work container); containerization is the separation mechanism that enables selective wipe.","D":"Application allowlisting controls which apps can run; workspace isolation is about separation of contexts."}},
  {"id":386,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which action should be taken with default accounts (like 'admin' or 'guest') found on newly deployed network devices?","options":{"A":"Leave them unchanged for management convenience","B":"Disable or rename them and change default credentials","C":"Add them to the admin group","D":"Use them for monitoring-only tasks"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"Default accounts with well-known names and passwords are targeted by attackers. They should be disabled or renamed, and default credentials must be changed immediately during deployment.","A":"Leaving default accounts unchanged is a critical security risk; they are actively targeted.","B":"Correct. Default accounts must be disabled or renamed with credentials changed during initial setup.","C":"Adding default accounts to admin groups increases risk; they should be secured or disabled.","D":"Using default accounts for monitoring doesn't address the known-credentials vulnerability."}},
  {"id":387,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which biometric authentication method is MOST resistant to spoofing using a photograph?","options":{"A":"2D facial recognition","B":"Fingerprint scanner","C":"3D facial recognition with liveness detection","D":"Signature verification"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"3D facial recognition with liveness detection maps the three-dimensional structure of a face and requires proof of being a real, living person (blinking, head movement), defeating photograph spoofing.","A":"2D facial recognition can be fooled by photographs and doesn't detect liveness.","B":"Fingerprint scanners can be spoofed with artificial fingerprints; they're not photograph-resistant.","C":"Correct. 3D facial recognition with liveness detection is most resistant to photograph spoofing.","D":"Signature verification can be forged; not biometric face recognition."}},
  {"id":388,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"An organization wants continuous visibility into its external attack surface as it changes. Which practice BEST supports this?","options":{"A":"Annual penetration test","B":"Continuous attack surface monitoring","C":"Monthly vulnerability scan","D":"Quarterly security audit"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Continuous attack surface monitoring (ASM) provides real-time discovery and tracking of internet-facing assets, detecting new exposures as cloud resources, subdomains, and services are added or changed.","A":"Annual penetration tests are point-in-time; they miss changes that occur between tests.","B":"Correct. Continuous ASM provides real-time visibility into the evolving external attack surface.","C":"Monthly scans provide periodic snapshots; continuous monitoring catches changes in real time.","D":"Quarterly audits are periodic; continuous monitoring tracks changes as they happen."}},
  {"id":389,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which security feature prevents scripts from loading resources (images, scripts) from unauthorized external domains?","options":{"A":"CORS","B":"Content Security Policy (CSP)","C":"HSTS","D":"X-Frame-Options"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"CSP (Content Security Policy) is a response header that specifies which sources are allowed to load scripts, images, stylesheets, and other resources, preventing injection attacks and data exfiltration via unauthorized domains.","A":"CORS controls which domains can make cross-origin requests; CSP controls which resources the page can load.","B":"Correct. CSP restricts where resources can be loaded from, mitigating XSS and data injection.","C":"HSTS enforces HTTPS protocol; it doesn't control resource loading.","D":"X-Frame-Options prevents framing; it doesn't control external resource loading."}},
  {"id":390,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which authentication protocol provides centralized authentication for UNIX/Linux systems using Kerberos tickets?","options":{"A":"RADIUS","B":"LDAP","C":"Active Directory with Kerberos","D":"OAuth 2.0"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Active Directory uses Kerberos as its authentication protocol, providing centralized authentication with ticket-based SSO for domain-joined Windows and Linux (via SSSD or similar) systems.","A":"RADIUS provides centralized authentication for network access; typically used with network devices.","B":"LDAP provides directory lookup services; Kerberos is the authentication protocol used with Active Directory.","C":"Correct. Active Directory with Kerberos provides centralized ticket-based authentication for domain systems.","D":"OAuth 2.0 handles web application authorization delegation; not UNIX/Linux Kerberos authentication."}},
  {"id":391,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which SIEM use case detects when the same user account logs in from two geographically distant locations within an impossibly short time?","options":{"A":"Brute force detection","B":"Impossible travel detection","C":"Lateral movement detection","D":"Data exfiltration detection"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Impossible travel detection flags when an account logs in from two locations that cannot be reached in the time between login events (e.g., New York and London within 5 minutes), indicating credential theft.","A":"Brute force detection identifies repeated failed logins; impossible travel detects spatial-temporal anomalies.","B":"Correct. Impossible travel detects two logins from geographically distant locations in an impossibly short time.","C":"Lateral movement detection identifies authentication events between internal systems.","D":"Data exfiltration detection identifies unusual outbound data transfers."}},
  {"id":392,"domain":4,"subdomain":"4.7","objective":"Explain the importance of automation and orchestration","stem":"Which security practice integrates security testing and checks directly into the CI/CD pipeline so vulnerabilities are caught before code is deployed?","options":{"A":"Penetration testing","B":"DevSecOps / Shift-left security","C":"Security operations center","D":"Compliance auditing"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"DevSecOps (shift-left security) integrates security testing (SAST, DAST, dependency scanning) into the development pipeline, catching vulnerabilities early in the software development lifecycle before deployment.","A":"Penetration testing is typically done post-development; shift-left integrates testing earlier.","B":"Correct. DevSecOps/shift-left integrates security testing into the CI/CD pipeline.","C":"The SOC monitors running environments; DevSecOps integrates into development.","D":"Compliance auditing verifies controls; DevSecOps is about integrating security into development."}},
  {"id":393,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"Which concept requires that original digital evidence be preserved unmodified, with forensic analysis performed only on verified copies?","options":{"A":"Order of volatility","B":"Non-repudiation","C":"Evidence integrity / working copy principle","D":"Legal hold"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"The working copy (forensic copy) principle requires preserving original evidence intact and working only from verified copies. Hash verification confirms the copy matches the original before analysis begins.","A":"Order of volatility determines collection order (volatile first); working copy is about preserving originals.","B":"Non-repudiation prevents denial of actions; it's a security property not a forensic procedure.","C":"Correct. Analysis must be performed on forensic copies, with originals preserved unmodified.","D":"Legal hold preserves relevant records; working copy is about forensic analysis procedure."}},
  {"id":394,"domain":4,"subdomain":"4.9","objective":"Use data sources to support an investigation","stem":"A SIEM detects connections from internal hosts to known Tor exit nodes at unusual hours. This MOST likely indicates:","options":{"A":"Employees using a secure browser","B":"Possible data exfiltration or C2 using anonymizing network","C":"Normal VPN usage","D":"Software update traffic"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Connections to Tor exit nodes from corporate systems, especially at unusual hours, indicate possible use of anonymizing network for C2 communication or data exfiltration, bypassing normal monitoring.","A":"Legitimate secure browsing would typically use corporate-approved VPNs, not Tor.","B":"Correct. Tor connections from corporate hosts at odd hours suggest anonymized C2 or exfiltration.","C":"Normal VPN traffic goes to corporate VPN servers; Tor exit nodes are different infrastructure.","D":"Software updates connect to known vendor infrastructure, not Tor exit nodes."}},
  {"id":395,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which activity validates that a patch was successfully applied and the vulnerability is no longer exploitable?","options":{"A":"Threat hunting","B":"Penetration testing","C":"Patch verification scan","D":"Security audit"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"A patch verification scan (re-scan after patching) confirms that the vulnerability no longer appears in scanner results, validating that the patch was applied correctly and the risk has been remediated.","A":"Threat hunting searches for active compromises; it doesn't specifically verify patch application.","B":"Penetration testing could test whether a vulnerability is exploitable but is too broad for routine patch verification.","C":"Correct. Re-scanning after patching verifies the vulnerability is no longer detected.","D":"Security audits are broader assessments; patch verification is a targeted remediation validation."}},
  {"id":396,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"An attacker attempts to access sensitive internal APIs from the internet that should only be accessible from the internal network. Which control BEST prevents this?","options":{"A":"Strong API authentication","B":"Network segmentation with firewall blocking external access to internal APIs","C":"API rate limiting","D":"TLS encryption"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Network segmentation with firewall rules blocking external access to internal APIs is the most direct control — external requests to internal API endpoints are blocked at the network perimeter regardless of authentication.","A":"Strong authentication reduces risk but doesn't prevent access if the API endpoint is internet-reachable.","B":"Correct. Firewall rules blocking external access to internal APIs is the most effective network-level control.","C":"Rate limiting slows attackers but doesn't prevent access to the API endpoint.","D":"TLS encrypts traffic in transit but doesn't prevent unauthorized access to the endpoint."}},
  {"id":397,"domain":4,"subdomain":"4.2","objective":"Explain the security implications of proper hardware, software, and data asset management","stem":"A company requires all decommissioned servers to have certificates of destruction from an approved data destruction vendor. This satisfies which requirement?","options":{"A":"Asset lifecycle management — destruction documentation","B":"Backup verification","C":"Vulnerability management","D":"Incident response"},"correct_answer":"A","difficulty":2,"explanations":{"correct":"Certificates of destruction document that data on decommissioned hardware was properly destroyed according to standards, fulfilling the asset lifecycle management requirement for documented sanitization.","A":"Correct. Certificates of destruction document proper data sanitization as part of asset lifecycle management.","B":"Backup verification confirms backups are complete and restorable; unrelated to hardware destruction.","C":"Vulnerability management addresses software vulnerabilities; hardware destruction is asset lifecycle.","D":"Incident response handles security events; certificates of destruction are a lifecycle management document."}},
  {"id":398,"domain":4,"subdomain":"4.4","objective":"Explain security alerting and monitoring concepts and tools","stem":"Which security monitoring approach analyzes endpoint telemetry across an entire fleet to detect threats that individual endpoint tools might miss?","options":{"A":"SIEM with host log aggregation","B":"XDR (Extended Detection and Response)","C":"Passive network TAP","D":"Vulnerability scanner"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"XDR correlates telemetry from endpoints, networks, email, identity, and cloud sources, providing a unified view that detects cross-domain attacks that siloed tools like EDR or SIEM alone would miss.","A":"SIEM with host logs provides correlation but may lack the deep endpoint telemetry integration of XDR.","B":"Correct. XDR correlates telemetry across multiple security domains for comprehensive threat detection.","C":"Passive network TAP provides network traffic copies; not correlated endpoint telemetry.","D":"Vulnerability scanners identify vulnerabilities; not real-time threat detection."}},
  {"id":399,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"Which password policy control prevents users from changing their password to one they used within the last year?","options":{"A":"Minimum age","B":"Maximum age","C":"Password history","D":"Complexity requirements"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Password history stores previous password hashes and prevents reuse. Combined with a password minimum age, it forces users to use genuinely new passwords rather than cycling through old ones.","A":"Minimum age requires a password to be used for a minimum period before changing; it doesn't prevent historical reuse.","B":"Maximum age forces periodic password changes; it doesn't prevent using old passwords.","C":"Correct. Password history prevents reuse of previously used passwords.","D":"Complexity requirements enforce character types; they don't prevent reusing old passwords."}},
  {"id":400,"domain":4,"subdomain":"4.9","objective":"Use data sources to support an investigation","stem":"During a breach investigation, analysts compare the current running configuration of a router to its known-good configuration backup. What are they looking for?","options":{"A":"Performance bottlenecks","B":"Unauthorized configuration changes that could indicate attacker persistence","C":"Firmware update availability","D":"Network utilization statistics"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Comparing current configuration to the known-good baseline reveals unauthorized changes made by an attacker, such as added firewall rules, routing changes, added users, or modified access control lists used for persistence.","A":"Performance analysis uses traffic statistics; configuration comparison is for security investigation.","B":"Correct. Configuration comparison reveals unauthorized changes that may indicate attacker persistence.","C":"Firmware updates are a separate maintenance task; configuration comparison is for change detection.","D":"Network utilization comes from monitoring tools; configuration comparison examines security settings."}},
  {"id":401,"domain":4,"subdomain":"4.1","objective":"Apply common security techniques to computing resources","stem":"Which Linux hardening step disables direct root login via SSH, requiring users to log in with their user account and use sudo?","options":{"A":"Setting PermitRootLogin no in sshd_config","B":"Disabling the SSH service","C":"Setting MaxAuthTries 1","D":"Enabling password-based authentication"},"correct_answer":"A","difficulty":3,"explanations":{"correct":"Setting 'PermitRootLogin no' in /etc/ssh/sshd_config prevents direct root logins over SSH, forcing administrators to authenticate as a regular user and elevate with sudo, improving accountability.","A":"Correct. 'PermitRootLogin no' disables direct root SSH login.","B":"Disabling SSH removes all remote administration capability — too restrictive.","C":"MaxAuthTries 1 limits failed attempts but doesn't prevent root login specifically.","D":"Password authentication is the default; disabling root login is a separate hardening step."}},
  {"id":402,"domain":4,"subdomain":"4.5","objective":"Given a scenario, modify enterprise capabilities to enhance security","stem":"Which security control checks that software has not been modified since it was signed by the developer?","options":{"A":"Antivirus scanning","B":"Code signing verification","C":"File integrity monitoring","D":"Hash comparison"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Code signing uses digital signatures (developer's private key) to validate software authenticity. Verification uses the developer's public key to confirm the code hasn't been modified since signing.","A":"Antivirus uses signature databases to detect known malware; it doesn't verify developer signatures.","B":"Correct. Code signing verification confirms software authenticity and integrity using digital signatures.","C":"FIM detects changes to files after deployment; code signing validates at installation time.","D":"Hash comparison verifies file integrity but code signing provides cryptographic proof of the signer's identity in addition to integrity."}},
  {"id":403,"domain":4,"subdomain":"4.6","objective":"Implement and maintain identity and access management","stem":"A user is granted access to a project for 90 days. After 90 days, access is automatically revoked. This is an example of:","options":{"A":"Least privilege","B":"Time-based access control","C":"Mandatory access control","D":"Attribute-based access control"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Time-based access control grants access only for a defined time window, automatically revoking it after the period expires. It's a form of dynamic access management reducing standing access risks.","A":"Least privilege limits the scope of access; time-based control adds a temporal dimension.","B":"Correct. Time-limited access with automatic expiration is time-based access control.","C":"MAC enforces access via security labels; time-based access is a different dimension.","D":"ABAC uses multiple attributes; time-based access is a specific implementation of temporal attributes."}},
  {"id":404,"domain":4,"subdomain":"4.8","objective":"Explain appropriate incident response activities","stem":"An organization conducts a drill where the IR team responds to a simulated ransomware attack using actual systems in a test environment. This is which type of exercise?","options":{"A":"Tabletop exercise","B":"Parallel test","C":"Simulation / functional exercise","D":"Full interruption test"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"A simulation or functional exercise uses actual systems and procedures in a realistic test environment, providing hands-on practice without risking production. It is more realistic than tabletop but less disruptive than full interruption.","A":"Tabletop exercises are discussion-based; no systems are actually used.","B":"Parallel tests run the DR site alongside production; not specifically for IR simulation.","C":"Correct. A functional exercise/simulation uses real systems in a controlled test environment.","D":"Full interruption tests switch to actual DR operations; more disruptive than described."}},
  {"id":405,"domain":4,"subdomain":"4.3","objective":"Explain various activities associated with vulnerability management","stem":"Which vulnerability management document tracks discovered vulnerabilities, their severity, owner, remediation status, and target fix dates?","options":{"A":"Risk register","B":"Vulnerability register / tracker","C":"Asset inventory","D":"Security policy"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A vulnerability register (or vulnerability tracker) is a centralized list of identified vulnerabilities with metadata including severity, affected systems, owners, remediation actions, and target resolution dates for tracking progress.","A":"A risk register tracks organizational risks broadly; a vulnerability register specifically tracks technical vulnerabilities.","B":"Correct. A vulnerability register tracks discovered vulnerabilities through their remediation lifecycle.","C":"An asset inventory tracks hardware and software assets; not vulnerability remediation status.","D":"A security policy defines requirements; it doesn't track individual vulnerabilities."}},
]
